// masters/customer_master.js
// Customer master — 741 base records live in CUSTOMER_SEED_DATA below.
// No seeding step required: getAllCustomers() merges the static list with any
// localStorage additions/edits automatically.
//
// GROUPED MODEL:
//   Parent record   id = CUS-XXXX   — holds company name.
//   Location record id = CUS-XXXX-YY — individual GST registration / site.
//   If locations[] is non-empty, gst/city/state/address are null on the parent.
//   If locations[] is empty, gst/city/state/address live directly on the parent.

import { storageGet, storageSet, storageGetAll, storageKeys, storageRemove } from '../lib/storage.js';
import { nextCustomerId } from '../lib/id.js';
import { auditLog } from '../lib/audit.js';

export const CUSTOMER_KEY_PREFIX = 'customer.';

// ---------------------------------------------------------------------------
// One-time migration — clears stale localStorage customer data when the
// data version changes (e.g. switching from the old 933-record SAP seed to
// the current 741-record cleaned/grouped set).
// Bump this string whenever the base seed data is replaced wholesale.
// ---------------------------------------------------------------------------
const CUSTOMER_DATA_VERSION = 'v3-pins-741';
(function migrateIfNeeded() {
  if (storageGet('customer._version') === CUSTOMER_DATA_VERSION) return;
  storageKeys(CUSTOMER_KEY_PREFIX).forEach(k => storageRemove(k));
  storageSet('counter.customer', 741);
  storageSet('customer._version', CUSTOMER_DATA_VERSION);
})();

// Canonical field list — every saved record contains exactly these keys.
export const CUSTOMER_FIELDS = Object.freeze([
  'id',                 // Auto-generated CUS-NNNN (parent) or CUS-NNNN-YY (location)
  'name',               // Required — company name (on parent only)
  'gst',                // GST registration number (null on parent when locations[] is used)
  'city',               // City (null on parent when locations[] is used)
  'state',              // State (null on parent when locations[] is used)
  'address',            // Full address (null on parent when locations[] is used)
  'postal_code',        // 6-digit Indian PIN code
  'locations',          // Array of { id, gst, city, state, address, postal_code } — empty for single-site
  'phone',              // Optional — primary phone
  'email',              // Optional — primary email
  'contact',            // Optional — contact person name
  'default_gp_pct',     // Default GP% prefilled into new quotations — number, e.g. 20 (means 20%).
  'default_freight_id', // Links to FREIGHT_MASTER[].id
  'active',             // boolean — false means disabled; excluded from quotation pickers
  'created_at',         // ISO timestamp — set once at creation, never changed
  'updated_at',         // ISO timestamp — refreshed on every save
]);

/**
 * Save a customer record.
 * Pass an object without `id` to create; pass with existing `id` to update.
 * New customers are assigned the next ID after the seed range (CUS-0742+).
 * @param {object} data
 * @returns {object} The saved record.
 */
export function saveCustomer(data) {
  const isNew = !data.id;

  // Guard: keep the ID counter above the seed range so new records never
  // collide with the 741 static entries (CUS-0001 – CUS-0741).
  if (isNew) {
    const cur = storageGet('counter.customer') ?? 0;
    if (cur < CUSTOMER_SEED_DATA.length) storageSet('counter.customer', CUSTOMER_SEED_DATA.length);
  }

  const id       = isNew ? nextCustomerId() : data.id;
  const existing = isNew ? null : (storageGet(`${CUSTOMER_KEY_PREFIX}${id}`) ?? CUSTOMER_SEED_DATA.find(c => c.id === id) ?? null);

  // Track which numeric suffixes are already taken so new locations get unique IDs.
  const usedNums = new Set(
    (existing?.locations ?? [])
      .map(l => { const m = (l.id ?? '').match(/-(\d+)$/); return m ? parseInt(m[1], 10) : null; })
      .filter(n => n !== null)
  );
  const assignLocId = () => {
    let n = 1;
    while (usedNums.has(n)) n++;
    usedNums.add(n);
    return `${id}-${String(n).padStart(2, '0')}`;
  };

  const locations = Array.isArray(data.locations)
    ? data.locations.map(loc => ({
        id:          loc.id      || assignLocId(),
        gst:         loc.gst?.trim()         || null,
        email:       loc.email?.trim()       || null,
        phone:       loc.phone?.trim()       || null,
        city:        loc.city?.trim()        || null,
        state:       loc.state?.trim()       || null,
        address:     loc.address?.trim()     || null,
        postal_code: loc.postal_code?.trim() || null,
      }))
    : [];

  const hasLocations = locations.length > 0;

  const record = {
    id,
    name:               (data.name ?? '').trim(),
    gst:                hasLocations ? null : (data.gst?.trim()         || null),
    city:               hasLocations ? null : (data.city?.trim()        || null),
    state:              hasLocations ? null : (data.state?.trim()       || null),
    address:            hasLocations ? null : (data.address?.trim()     || null),
    postal_code:        hasLocations ? null : (data.postal_code?.trim() || null),
    locations,
    phone:              data.phone?.trim()   || null,
    email:              data.email?.trim()   || null,
    contact:            data.contact?.trim() || null,
    default_gp_pct:     data.default_gp_pct != null ? Number(data.default_gp_pct) : 20,
    default_freight_id: data.default_freight_id || null,
    active:             data.active !== false,
    created_at: existing?.created_at ?? new Date().toISOString(),
    updated_at: new Date().toISOString(),
  };

  storageSet(`${CUSTOMER_KEY_PREFIX}${id}`, record);
  auditLog({ entity: 'customer', entity_id: id, action: isNew ? 'created' : 'edited', diff: record });
  return record;
}

/**
 * Retrieve a single customer by ID.
 * localStorage record takes precedence over the static seed (covers edits).
 * @param {string} id - e.g. 'CUS-0001'
 * @returns {object|null}
 */
export function getCustomer(id) {
  if (!id) return null;
  return storageGet(`${CUSTOMER_KEY_PREFIX}${id}`)
      ?? CUSTOMER_SEED_DATA.find(c => c.id === id)
      ?? null;
}

/**
 * Disable a customer — writes active:false to localStorage.
 * Disabled customers are excluded from quotation customer pickers.
 * @param {string} id
 * @returns {object|null}
 */
export function disableCustomer(id) {
  const c = getCustomer(id);
  if (!c) return null;
  return saveCustomer({ ...c, active: false });
}

/**
 * Re-enable a previously disabled customer.
 * @param {string} id
 * @returns {object|null}
 */
export function enableCustomer(id) {
  const c = getCustomer(id);
  if (!c) return null;
  return saveCustomer({ ...c, active: true });
}

/**
 * Retrieve all customers sorted by CUS-NNNN ID (matches the order in CUSTOMER_SEED_DATA).
 * Merges the static seed list with localStorage additions/edits.
 * localStorage records (edits + new) always shadow the matching seed entry.
 * @param {boolean} includeInactive — pass true to include disabled customers
 * @returns {object[]}
 */
export function getAllCustomers(includeInactive = false) {
  const lsRecords = storageGetAll(CUSTOMER_KEY_PREFIX).filter(c => c.id !== '_version');
  const lsById    = new Map(lsRecords.map(c => [c.id, c]));
  const seedIds   = new Set(CUSTOMER_SEED_DATA.map(c => c.id));
  const cusNum    = id => parseInt((id ?? '').replace(/^CUS-/, ''), 10) || 0;

  const seedPart = CUSTOMER_SEED_DATA.map(c => lsById.get(c.id) ?? c);
  const newPart  = lsRecords
    .filter(c => !seedIds.has(c.id))
    .sort((a, b) => cusNum(a.id) - cusNum(b.id));

  const all = [...seedPart, ...newPart];
  return includeInactive ? all : all.filter(c => c.active !== false);
}

/**
 * Search customers by name, city, state, or GST (case-insensitive, partial match).
 * Also searches inside locations[] for city/state/gst matches.
 * Results preserve the same CUS-NNNN ID order as getAllCustomers().
 * Returns all customers when query is empty or blank.
 * @param {string} query
 * @returns {object[]}
 */
export function searchCustomers(query) {
  if (!query?.trim()) return getAllCustomers();
  const q = query.toLowerCase();
  return getAllCustomers().filter(c => {
    if (c.name?.toLowerCase().includes(q))        return true;
    if (c.city?.toLowerCase().includes(q))        return true;
    if (c.state?.toLowerCase().includes(q))       return true;
    if (c.gst?.toLowerCase().includes(q))         return true;
    if (c.postal_code?.toLowerCase().includes(q)) return true;
    return c.locations?.some(loc =>
      loc.city?.toLowerCase().includes(q)        ||
      loc.state?.toLowerCase().includes(q)       ||
      loc.gst?.toLowerCase().includes(q)         ||
      loc.postal_code?.toLowerCase().includes(q)
    );
  });
}

/**
 * Check whether a customer with the given ID exists.
 * @param {string} id
 * @returns {boolean}
 */
export function customerExists(id) {
  return getCustomer(id) !== null;
}

/**
 * Resolve the billing address for a customer selection.
 * Pass locationId when the customer has multiple locations.
 * Returns { gst, city, state, address } — the active site's values.
 * @param {string} customerId
 * @param {string|null} locationId
 * @returns {object|null}
 */
export function resolveCustomerSite(customerId, locationId = null) {
  const c = getCustomer(customerId);
  if (!c) return null;
  if (c.locations?.length > 0) {
    const loc = locationId
      ? c.locations.find(l => l.id === locationId)
      : c.locations[0];
    return loc ?? null;
  }
  return { gst: c.gst, city: c.city, state: c.state, address: c.address, postal_code: c.postal_code };
}

/**
 * Return a flat, alphabetically sorted list of all customer-location entries.
 * Single-site customer → one entry with location_id null.
 * Multi-site customer  → one entry per location, labelled "Name — City, State".
 * Use option_key as the <select> value; parse it with parseOptionKey() to get
 * the parent customer_id and location_id separately.
 * @param {boolean} includeInactive
 * @returns {{ option_key: string, customer_id: string, location_id: string|null, name: string }[]}
 */
export function getAllCustomerLocations(includeInactive = false) {
  const entries = [];
  for (const c of getAllCustomers(includeInactive)) {
    if (c.locations?.length > 0) {
      for (const loc of c.locations) {
        const parts = [loc.city, loc.state].filter(Boolean);
        const suffix = parts.length ? ` — ${parts.join(', ')}` : '';
        entries.push({ option_key: `${c.id}|${loc.id}`, customer_id: c.id, location_id: loc.id, name: `${c.name}${suffix}` });
      }
    } else {
      entries.push({ option_key: c.id, customer_id: c.id, location_id: null, name: c.name });
    }
  }
  return entries.sort((a, b) => (a.name ?? '').localeCompare(b.name ?? '', 'en', { sensitivity: 'base' }));
}

/**
 * Parse a customer option_key back into its components.
 * "CUS-0001"            → { customer_id: 'CUS-0001', location_id: null }
 * "CUS-0001|CUS-0001-02"→ { customer_id: 'CUS-0001', location_id: 'CUS-0001-02' }
 * @param {string} key
 * @returns {{ customer_id: string|null, location_id: string|null }}
 */
export function parseOptionKey(key) {
  if (!key) return { customer_id: null, location_id: null };
  const idx = key.indexOf('|');
  if (idx === -1) return { customer_id: key, location_id: null };
  return { customer_id: key.slice(0, idx), location_id: key.slice(idx + 1) };
}

